    public static function import(int $bolao_id, bool $overwrite = false): array {
        global $wpdb;
        $inserted = 0;
        $updated = 0;
        $skipped = 0;
        $now = current_time('mysql');
        foreach (self::schedule() as $game) {
            $exists = $wpdb->get_row($wpdb->prepare(
                "SELECT id FROM " . rsb_table('jogos') . " WHERE bolao_id=%d AND codigo_jogo=%s",
                $bolao_id,
                $game['codigo_jogo']
            ));
            $payload = [
                'bolao_id' => $bolao_id,
                'codigo_jogo' => sanitize_text_field($game['codigo_jogo']),
                'fase' => class_exists('RSB_WorldCup_Format') ? RSB_WorldCup_Format::normalize_phase(sanitize_text_field($game['fase'])) : sanitize_text_field($game['fase']),
                'grupo' => sanitize_text_field($game['grupo']),
                'rodada' => (strpos(mb_strtolower((string)$game['rodada']), '32 avos') !== false) ? '16-avos de final / Rodada de 32' : sanitize_text_field($game['rodada']),
                'data_jogo' => sanitize_text_field($game['data_jogo']),
                'hora_jogo' => sanitize_text_field($game['hora_jogo']),
                'time_mandante' => sanitize_text_field($game['time_mandante']),
                'time_visitante' => sanitize_text_field($game['time_visitante']),
                'local_jogo' => sanitize_text_field($game['local_jogo']),
                'status' => sanitize_text_field($game['status']),
                'updated_at' => $now,
            ];
            if ($exists && !$overwrite) {
                if (self::should_refresh_defined_knockout_game($game)) {
                    $updated += self::refresh_defined_knockout_game((int) $exists->id, $game, $now);
                }
                $skipped++;
                continue;
            }
            if ($exists && $overwrite) {
                $wpdb->update(rsb_table('jogos'), $payload, ['id' => (int)$exists->id]);
                $updated++;
                continue;
            }
            $payload['created_at'] = $now;
            $wpdb->insert(rsb_table('jogos'), $payload);
            $inserted++;
        }
        rsb_log('importar_copa_2026', 'jogos', $bolao_id, null, ['inserted'=>$inserted,'updated'=>$updated,'skipped'=>$skipped]);
        return ['inserted'=>$inserted,'updated'=>$updated,'skipped'=>$skipped,'total'=>count(self::schedule())];
    }

    private static function should_refresh_defined_knockout_game(array $game): bool {
        return in_array((string) ($game['codigo_jogo'] ?? ''), ['M097', 'M098', 'M099', 'M100'], true);
    }

    private static function refresh_defined_knockout_game(int $game_id, array $game, string $now): int {
        global $wpdb;
        $payload = [
            'time_mandante' => sanitize_text_field($game['time_mandante']),
            'time_visitante' => sanitize_text_field($game['time_visitante']),
            'status' => sanitize_text_field($game['status']),
            'updated_at' => $now,
        ];
        $ok = false !== $wpdb->update(rsb_table('jogos'), $payload, ['id' => $game_id]);
        return $ok ? 1 : 0;
    }

}
